// 1. Get the array of leads safely
// We check the root, or if the data is wrapped inside 'body'
const input = items[0].json;
const leads = input.leads || (input.body && input.body.leads) || [];

// Safety check: Did we actually get any leads?
if (leads.length === 0) {
  return {
    json: {
      summary: "No leads found in this batch.",
      total_revenue: "$0",
      lead_names: "None"
    }
  };
}

// 2. Filter out bad data (e.g., leads with 0 value)
const validLeads = leads.filter(lead => lead.value > 0);

// 3. Count how many leads we have
const totalCount = validLeads.length;

// 4. Calculate total value using reduce
const totalValue = validLeads.reduce((sum, lead) => sum + lead.value, 0);

// 5. Create a clean list of names
const namesList = validLeads.map(lead => lead.name).join(", ");

// 6. Return a single summary object
return {
  json: {
    summary: `Daily Digest: ${totalCount} new qualified leads today!`,
    total_revenue: `$${totalValue}`,
    lead_names: namesList
  }
};
